import{_ as t,o,c as a,ag as s}from"./chunks/framework.DLWhSH9p.js";const p=JSON.parse(`{"title":"The Cloud is Just Someone Else's Computer","description":"","frontmatter":{"id":"script-final-01","title":"The Cloud is Just Someone Else's Computer","type":"long","status":"final","tags":["cloud","AWS","humor","explainer"],"created":"2025-06-15T10:30:00.000Z","updated":"2025-06-20T16:45:00.000Z","word_count":1247},"headers":[],"relativePath":"seed/channels/demo-channel/scripts/final/script-final-01.md","filePath":"seed/channels/demo-channel/scripts/final/script-final-01.md"}`),n={name:"seed/channels/demo-channel/scripts/final/script-final-01.md"};function r(i,e,l,h,u,d){return o(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="the-cloud-is-just-someone-else-s-computer" tabindex="-1">The Cloud is Just Someone Else&#39;s Computer <a class="header-anchor" href="#the-cloud-is-just-someone-else-s-computer" aria-label="Permalink to &quot;The Cloud is Just Someone Else&#39;s Computer&quot;">​</a></h1><h3 id="the-hook" tabindex="-1">The Hook <a class="header-anchor" href="#the-hook" aria-label="Permalink to &quot;The Hook&quot;">​</a></h3><p><em>(Alex at desk, surrounded by server cables, looking exhausted)</em></p><p>Let me tell you something that will either blow your mind or make you very, very angry. The cloud — that magical, ethereal, omnipresent thing that powers basically everything you use — is just someone else&#39;s computer. That&#39;s it. That&#39;s the whole thing.</p><hr><h3 id="what-even-is-the-cloud" tabindex="-1">What Even Is &quot;The Cloud&quot;? <a class="header-anchor" href="#what-even-is-the-cloud" aria-label="Permalink to &quot;What Even Is &quot;The Cloud&quot;?&quot;">​</a></h3><p><strong>Alex:</strong> Here&#39;s the thing. When someone says &quot;we&#39;re moving to the cloud,&quot; what they actually mean is &quot;we&#39;re going to pay Amazon to let us use their computers instead of buying our own.&quot;</p><p><em>(walks to whiteboard)</em></p><p>Think of it like housing. You can:</p><ol><li><strong>Buy a house</strong> (on-premise servers) — expensive upfront, you fix everything yourself, but it&#39;s yours</li><li><strong>Rent an apartment</strong> (cloud computing) — someone else owns it, maintains it, and you pay monthly</li><li><strong>Stay at a hotel</strong> (serverless) — you show up, use what you need, leave, and get charged by the hour</li></ol><p><strong>Alex:</strong> Most startups go straight to the hotel option and then act surprised when the bill arrives. &quot;I just left the lights on overnight and now I owe Jeff Bezos forty thousand dollars.&quot;</p><hr><h3 id="the-big-three" tabindex="-1">The Big Three <a class="header-anchor" href="#the-big-three" aria-label="Permalink to &quot;The Big Three&quot;">​</a></h3><p><em>(three logos appear on screen)</em></p><p>There are three major cloud providers, and choosing between them is like choosing a phone carrier — they all do the same thing, they all have confusing pricing, and switching is a nightmare.</p><p><strong>AWS</strong> — The oldest, most feature-rich, most confusing. It has over 200 services. Nobody knows what all of them do. Not even Amazon.</p><p><strong>Azure</strong> — Microsoft&#39;s cloud. Great if you already sold your soul to the Microsoft ecosystem. Active Directory goes brrrr.</p><p><strong>Google Cloud (GCP)</strong> — The smallest of the three but arguably the best tech. The problem is Google might just... cancel it one day. They do that.</p><hr><h3 id="why-everyone-is-moving-to-the-cloud" tabindex="-1">Why Everyone is Moving to the Cloud <a class="header-anchor" href="#why-everyone-is-moving-to-the-cloud" aria-label="Permalink to &quot;Why Everyone is Moving to the Cloud&quot;">​</a></h3><p><em>(back at desk, leaning back)</em></p><p><strong>Alex:</strong> Here&#39;s why the cloud actually makes sense for most people:</p><p><strong>Scalability.</strong> If your app goes viral at 3 AM, the cloud automatically spins up more servers. Try doing that with a rack in your closet.</p><p><strong>Cost.</strong> You only pay for what you use. In theory. In practice, you forget to turn off that development database and it runs for six months.</p><p><em>(stage direction: show a &quot;billing alert&quot; notification)</em></p><p><strong>Reliability.</strong> AWS has data centers on every continent except Antarctica. Although at this point, I wouldn&#39;t be surprised if there&#39;s an S3 bucket at the South Pole.</p><p><strong>Security.</strong> This one&#39;s actually real. AWS and Azure spend more on security than most countries spend on their military. Your data is probably safer in the cloud than on your laptop, and we both know your laptop password is &quot;password123.&quot;</p><hr><h3 id="the-downsides-nobody-talks-about" tabindex="-1">The Downsides Nobody Talks About <a class="header-anchor" href="#the-downsides-nobody-talks-about" aria-label="Permalink to &quot;The Downsides Nobody Talks About&quot;">​</a></h3><p><em>(serious face, dramatic lighting)</em></p><p><strong>Vendor lock-in.</strong> Once you build everything on AWS, leaving is like trying to switch banks — technically possible but emotionally devastating.</p><p><strong>Complexity.</strong> The cloud dashboard looks like the cockpit of a spaceship designed by a committee. There are buttons you should never press and warnings you should never ignore.</p><p><strong>The bill.</strong> Cloud pricing is an art form. Not in a good way. In a &quot;modern art where the canvas is blank and it costs twelve million dollars&quot; way.</p><p><em>(pulls up a fake AWS bill)</em></p><p><strong>Alex:</strong> This is my development environment bill from last month. I was testing something. &quot;Testing.&quot; That&#39;s what I told my accountant. She didn&#39;t believe me either.</p><hr><h3 id="when-you-shouldn-t-use-the-cloud" tabindex="-1">When You Shouldn&#39;t Use the Cloud <a class="header-anchor" href="#when-you-shouldn-t-use-the-cloud" aria-label="Permalink to &quot;When You Shouldn&#39;t Use the Cloud&quot;">​</a></h3><p><em>(standing, pointing at camera)</em></p><p>Not everything needs to be in the cloud. Here&#39;s when you should keep it simple:</p><ul><li><strong>Personal projects</strong> — A $5 VPS from DigitalOcean or Hetzner will handle more traffic than your blog will ever see</li><li><strong>Sensitive data</strong> — Some industries require data to stay on-premise. Healthcare, finance, government. The cloud is great until regulators come knocking.</li><li><strong>Simple websites</strong> — If it&#39;s a static site, just use GitHub Pages. It&#39;s free. You&#39;re welcome.</li></ul><hr><h3 id="the-takeaway" tabindex="-1">The Takeaway <a class="header-anchor" href="#the-takeaway" aria-label="Permalink to &quot;The Takeaway&quot;">​</a></h3><p><em>(back at desk, cables now neatly organized)</em></p><p>The cloud is a tool. A powerful, expensive, occasionally terrifying tool. Like a chainsaw. Incredibly useful when you need it. Absolutely overkill for cutting a sandwich.</p><p><strong>Alex:</strong> Learn the basics. Understand what you&#39;re paying for. And for the love of everything holy, set up billing alerts.</p><p><em>(leans into camera)</em></p><p>Because the only thing scarier than a production outage... is the email that says &quot;Your AWS bill for this month is $47,000.&quot;</p><p><em>(cut to black)</em></p><hr><p><em>Subscribe for more tech explainers that won&#39;t put you to sleep. Probably.</em></p>',50)])])}const m=t(n,[["render",r]]);export{p as __pageData,m as default};
